module adder_32bit(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);
// Copy your CLA 16-bit adder code from Homework 3
wire C1;
wire [16:1] S_0;
wire [16:0] G, P;
// Add the first 16 bits
assign G[15:0] = A[15:0] & B[15:0];
assign P[15:0] = A[15:0] | B[15:0];
assign C1 = G[0] | P[0] & (G[1] | P[1] & (G[2] | P[2] & (G[3] | P[3] & (G[4] | P[4] & (G[5] | P[5] & (G[6] | P[6] & (G[7] | P[7] & (G[8] | P[8] & (G[9] | P[9] & (G[10] | P[10] & (G[11] | P[11] & (G[12] | P[12] & (G[13] | P[13] & (G[14] | P[14] & G[15])))))))))))));
assign S_0[15:0] = A[15:0] ^ B[15:0] ^ {C1, P[15:1]};
// Add the last 16 bits
wire C1_optimized, G0, P0;
assign G0 = A[31] & B[31];
assign P0 = A[31] | B[31];
assign C1_optimized = G0 | P0 & C1;
wire [15:1] S_1;
assign S_1[15:1] = A[31:16] ^ B[31:16] ^ {C1_optimized, P[31:16]};
// Concatenate the results of the two previous adders to form the final result.
assign S[32:1] = {S_1, S_0};
// Assign the carry-out output to the MSB of the second adder.
assign C32 = C1_optimized;
endmodule
